import { get, isNil } from 'lodash-es';

import { ColorRuleProps, MatchValue } from '../../../core/types/color-rule.js';
import type {
  ColorRuleValidator,
  RectDatapointInternal,
} from '../../types/xy-chart-internals.js';

export const rectDatapointMatchesColorRule = (
  datapoint: RectDatapointInternal,
  rule: ColorRuleProps,
  isValid: ColorRuleValidator,
): boolean => {
  const accessor = rule.valueAccessor ?? 'value';
  const subject = get(datapoint, accessor) as MatchValue;
  return !isNil(subject) && isValid(subject, rule.comparator, rule.matchValue);
};
